import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff, UserPlus, Zap } from 'lucide-react';

/* Autofill bg colour — must be a real hex/rgb, CSS vars don't work inside webkit inset shadow */
const AUTOFILL_BG   = '#111318';  /* matches --card-bg / --bg-secondary in dark theme */
const AUTOFILL_TEXT = '#ffffff';

const RegisterPage = () => {
  const [formData, setFormData] = useState({ name: '', email: '', password: '', confirmPassword: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [focused, setFocused] = useState(null);

  const { register } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!formData.name || !formData.email || !formData.password || !formData.confirmPassword) {
      toast.error('Please fill in all fields');
      return;
    }

    if (formData.password !== formData.confirmPassword) {
      toast.error('Passwords do not match');
      return;
    }

    if (formData.password.length < 6) {
      toast.error('Password must be at least 6 characters');
      return;
    }

    setLoading(true);
    try {
      await register(formData);
      toast.success('Account created successfully!');
      navigate('/login');
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  /* Shared autofill-proof input style */
  const inputStyle = (extra = {}) => ({
    width: '100%',
    boxSizing: 'border-box',
    WebkitBoxShadow: `0 0 0px 1000px ${AUTOFILL_BG} inset`,
    WebkitTextFillColor: AUTOFILL_TEXT,
    caretColor: 'var(--accent-primary)',
    ...extra,
  });

  const labelStyle = (field) => ({
    display: 'block', 
    fontSize: '0.58rem', 
    fontWeight: 700,
    textTransform: 'uppercase', 
    letterSpacing: '0.18em',
    color: focused === field ? 'var(--accent-primary)' : 'var(--text-muted)',
    marginBottom: '0.35rem', 
    transition: 'color 0.2s ease',
  });

  const PasswordField = ({ id, label, value, onChange, show, onToggle, autoComplete }) => (
    <div>
      <label htmlFor={id} style={labelStyle(id)}>
        {label}
      </label>
      <div style={{ position: 'relative' }}>
        <input
          id={id}
          type={show ? 'text' : 'password'}
          placeholder="••••••••"
          value={value}
          onChange={onChange}
          onFocus={() => setFocused(id)}
          onBlur={() => setFocused(null)}
          autoComplete={autoComplete}
          className="cyber-input"
          required
          style={inputStyle({ paddingRight: '3rem' })}
        />
        <button
          type="button"
          onClick={onToggle}
          aria-label={show ? 'Hide password' : 'Show password'}
          style={{
            position: 'absolute',
            right: '0.875rem',
            top: '50%',
            transform: 'translateY(-50%)',
            background: 'none',
            border: 'none',
            padding: 0,
            cursor: 'pointer',
            color: 'var(--text-muted)',
            display: 'flex',
            alignItems: 'center',
            transition: 'color 0.2s ease',
          }}
          onMouseEnter={e => e.currentTarget.style.color = 'var(--accent-primary)'}
          onMouseLeave={e => e.currentTarget.style.color = 'var(--text-muted)'}
        >
          {show ? <EyeOff size={15} /> : <Eye size={15} />}
        </button>
      </div>
    </div>
  );

  return (
    <div style={{
      flex: 1,
      minHeight: 0,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '2rem 1rem',
      boxSizing: 'border-box',
      position: 'relative',
      background: 'radial-gradient(ellipse at 50% 40%, var(--bg-secondary) 0%, var(--bg-main) 70%)',
    }}>
      {/* Ambient glows */}
      <div aria-hidden="true" style={{
        position: 'fixed', top: '-80px', left: '-80px',
        width: '320px', height: '320px',
        background: 'var(--accent-glow)', borderRadius: '50%',
        filter: 'blur(80px)', opacity: 0.5, pointerEvents: 'none', zIndex: 0,
      }} />
      <div aria-hidden="true" style={{
        position: 'fixed', bottom: '-60px', right: '-60px',
        width: '260px', height: '260px',
        background: 'var(--accent-glow)', borderRadius: '50%',
        filter: 'blur(90px)', opacity: 0.25, pointerEvents: 'none', zIndex: 0,
      }} />

      {/* Register Card */}
      <div
        className="reveal-node"
        style={{
          position: 'relative',
          zIndex: 1,
          width: '100%',
          maxWidth: '400px',
          padding: '2rem',
          borderRadius: '20px',
          backdropFilter: 'blur(20px)',
          WebkitBackdropFilter: 'blur(20px)',
          background: 'var(--surface-glass)',
          border: '1px solid var(--surface-border)',
          boxShadow: 'var(--shadow-elevated)',
          overflow: 'hidden',
          transition: 'box-shadow 0.4s ease, border-color 0.4s ease',
        }}
        onMouseEnter={e => {
          e.currentTarget.style.boxShadow    = '0 0 40px var(--accent-glow), var(--shadow-elevated)';
          e.currentTarget.style.borderColor  = 'var(--accent-primary)';
        }}
        onMouseLeave={e => {
          e.currentTarget.style.boxShadow    = 'var(--shadow-elevated)';
          e.currentTarget.style.borderColor  = 'var(--surface-border)';
        }}
      >
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '1.75rem' }}>
          <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '0.8rem' }}>
            <div style={{
              width: '46px', height: '46px', borderRadius: '13px',
              background: 'var(--accent-muted)',
              border: '1px solid var(--accent-primary)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              boxShadow: '0 0 18px var(--accent-glow)',
            }}>
              <UserPlus size={20} color="var(--accent-primary)" />
            </div>
          </div>
          <h1 style={{
            fontSize: '1.4rem', fontWeight: 300, letterSpacing: '-0.02em',
            color: 'var(--text-primary)', margin: '0 0 0.3rem',
          }}>
            Create Account
          </h1>
          <p style={{
            fontSize: '0.58rem', textTransform: 'uppercase',
            letterSpacing: '0.22em', color: 'var(--text-muted)', margin: 0,
          }}>
            Start your financial journey
          </p>
        </div>

        <form onSubmit={handleSubmit} noValidate style={{ display: 'flex', flexDirection: 'column', gap: '0.9rem' }}>
          <div>
            <label htmlFor="register-name" style={labelStyle('name')}>
              Full Name
            </label>
            <input
              id="register-name"
              type="text"
              placeholder="John Doe"
              value={formData.name}
              onChange={e => setFormData({...formData, name: e.target.value})}
              onFocus={() => setFocused('name')}
              onBlur={() => setFocused(null)}
              autoComplete="name"
              className="cyber-input"
              required
              style={inputStyle()}
            />
          </div>

          <div>
            <label htmlFor="register-email" style={labelStyle('email')}>
              Email Address
            </label>
            <input
              id="register-email"
              type="email"
              placeholder="operator@finify.ai"
              value={formData.email}
              onChange={e => setFormData({...formData, email: e.target.value})}
              onFocus={() => setFocused('email')}
              onBlur={() => setFocused(null)}
              autoComplete="email"
              className="cyber-input"
              required
              style={inputStyle()}
            />
          </div>

          <PasswordField
            id="register-password"
            label="Master Key"
            value={formData.password}
            onChange={e => setFormData({...formData, password: e.target.value})}
            show={showPassword}
            onToggle={() => setShowPassword(v => !v)}
            autoComplete="new-password"
          />

          <PasswordField
            id="register-confirm-password"
            label="Confirm Master Key"
            value={formData.confirmPassword}
            onChange={e => setFormData({...formData, confirmPassword: e.target.value})}
            show={showConfirmPassword}
            onToggle={() => setShowConfirmPassword(v => !v)}
            autoComplete="new-password"
          />

          <button
            type="submit"
            className="cyber-btn"
            disabled={loading}
            style={{ marginTop: '0.2rem' }}
          >
            {loading
              ? <><Zap size={13} style={{ animation: 'pulse 1s ease-in-out infinite' }} /> INITIALIZING...</>
              : 'Initialize Node'
            }
          </button>
        </form>

        {/* Footer */}
        <div style={{
          marginTop: '1.25rem', paddingTop: '1rem',
          borderTop: '1px solid var(--surface-border)',
          textAlign: 'center',
        }}>
          <p style={{
            fontSize: '0.58rem', textTransform: 'uppercase',
            letterSpacing: '0.2em', color: 'var(--text-muted)', margin: 0,
          }}>
            Already have an account?{' '}
            <Link to="/login" style={{
              color: 'var(--accent-primary)', textDecoration: 'none',
              fontWeight: 700, transition: 'opacity 0.2s ease',
            }}
              onMouseEnter={e => e.currentTarget.style.opacity = '0.7'}
              onMouseLeave={e => e.currentTarget.style.opacity = '1'}
            >
              Sign in
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default RegisterPage;
